sp_css.css:
/* Change Homepage Header Font */
#homepage-search > div > h2 {
  font-family:'DynaPuff';
}
/* Change H2 Font */
div.panel-heading > h2 {
  font-family:'Varela Round';
}
/* Change H3 Font */
h3,h2,h1 {
 font-family:'Varela Round';
}
.panel-heading
{
font-family:'Varela Round';
}
ul,li
{
font-family:'Varela Round';
}
.panel-body
{
font-family:'Varela Round';
}
p
{
 font-family:'Varela Round';
}
body
{
 font-family:'Varela Round';
}
